svg.script:
    let currentX = null;
    let laneOffset = 0;
    let speedAngle = -120;
    let diffAngle = 0;

    function clamp(v, lo, hi) {
      return Math.max(lo, Math.min(hi, v));
    }

    function animate() {
      const targetNode = document.getElementById("front_target_x");
      const roadSpeedNode = document.getElementById("road_speed_value");
      const egoSpeedNode = document.getElementById("ego_speed_value");
      const diffNode = document.getElementById("speed_diff_angle");

      const car = document.getElementById("front_car");
      const label = document.getElementById("front_label");
      const lane = document.getElementById("lane");
      const speedNeedle = document.getElementById("speed_needle");
      const diffNeedle = document.getElementById("diff_needle");
      const egoSpeedDisplay = document.getElementById("ego_speed_display");

      /* front car */
      if (targetNode && car) {
        const targetX = parseFloat(targetNode.textContent);
        if (!isNaN(targetX)) {
          if (currentX === null) currentX = targetX;
          currentX = currentX + (targetX - currentX) * 0.04;
          car.setAttribute("x", currentX);
          if (label) label.setAttribute("x", currentX + 50);

          if (currentX > 1000) {
            car.setAttribute("visibility", "hidden");
            if (label) label.setAttribute("visibility", "hidden");
          } else {
            car.setAttribute("visibility", "visible");
            if (label) label.setAttribute("visibility", "visible");
          }
        }
      }

      /* road flow */
      if (roadSpeedNode && lane) {
        const roadSpeed = parseFloat(roadSpeedNode.textContent);
        if (!isNaN(roadSpeed)) {
          laneOffset = laneOffset + Math.max(0.5, roadSpeed * 0.1);
          lane.setAttribute("stroke-dashoffset", laneOffset);
        }
      }

/* ego speed dial: 0..vmax maps to -120..120 degrees */
if (egoSpeedNode && speedNeedle) {
  const s = parseFloat(egoSpeedNode.textContent);
  const maxNode = document.getElementById("vmax_value");
  const vmax = maxNode ? parseFloat(maxNode.textContent) : 40;

  if (!isNaN(s) && !isNaN(vmax) && vmax > 0) {
    const targetAngle =
        -120 + (clamp(s, 0, vmax) * 240 / vmax);

    speedAngle =
        speedAngle + (targetAngle - speedAngle) * 0.08;

    speedNeedle.setAttribute(
        "transform",
        "rotate(" + speedAngle + ")"
    );

    if (egoSpeedDisplay) {
      egoSpeedDisplay.textContent =
          Math.round(s);
    }
  }
}

      /* speed difference dial: negative=red, positive=green */
      if (diffNode && diffNeedle) {
        const a = parseFloat(diffNode.textContent);
        if (!isNaN(a)) {
          const targetDiff = clamp(a, -90, 90);
          diffAngle = diffAngle + (targetDiff - diffAngle) * 0.08;
          diffNeedle.setAttribute("transform", "rotate(" + diffAngle + ")");
        }
      }

      requestAnimationFrame(animate);
    }

    requestAnimationFrame(animate);
